class Solution:
    def findTheLongestBalancedSubstring(self, s: str) -> int:
        max_len, zeros, ones = 0, 0, 0
        for c in s:
            if c == '0':
                zeros += 1
            else:
                ones += 1
                if zeros > 0:
                    zeros -= 1
                    max_len = max(max_len, zeros + ones)
        return max_len
